def select_next_node(cur_truck_pos, depot_pos, all_truck_pos, unvisited_customers, current_time, truck_speed, time_windows):
    def euclidean_distance(pos1, pos2):
        return np.linalg.norm(pos1 - pos2)

    def calculate_future_cost(path_choice, remaining_customers, future_time_windows, depth=2):
        # Simple recursive predictor for future routing cost
        if depth == 0 or not remaining_customers:
            return 0
        best_future_cost = float('inf')
        for i, customer in enumerate(remaining_customers):
            time_to_customer = euclidean_distance(path_choice, customer) / truck_speed
            future_arrival = current_time + time_to_customer
            start, end = future_time_windows[i]
            if future_arrival < start:
                wait_cost = (start - future_arrival) * 0.3
            elif future_arrival > end:
                wait_cost = (future_arrival - end) * 10
            else:
                wait_cost = 0
            rec_future_cost = calculate_future_cost(customer, remaining_customers[:i] + remaining_customers[i+1:], future_time_windows[:i] + future_time_windows[i+1:], depth-1)
            total_cost = wait_cost + rec_future_cost
            if total_cost < best_future_cost:
                best_future_cost = total_cost
        return best_future_cost

    best_node = None
    best_cost = float('inf')

    for idx, customer in enumerate(unvisited_customers):
        travel_time = euclidean_distance(cur_truck_pos, customer) / truck_speed
        possible_arrival_time = current_time + travel_time
        window_start, window_end = time_windows[idx]

        if possible_arrival_time > window_end:  # Skip if the window will be missed
            continue

        future_cost = calculate_future_cost(customer, unvisited_customers[:idx] + unvisited_customers[idx+1:], time_windows[:idx] + time_windows[idx+1:])

        if possible_arrival_time < window_start:
            current_cost = (window_start - possible_arrival_time) * 0.3 + future_cost  # Less penalty for waiting
        elif window_start <= possible_arrival_time <= window_end:
            current_cost = future_cost  # No additional cost if arriving during the window
        else: # Late arrival case after eliminating over late
            current_cost = (possible_arrival_time - window_end) * 10 + future_cost

        if current_cost < best_cost:
            best_cost = current_cost
            best_node = idx

    return best_node
